import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { Estimate } from '../../../core/models';
import { formatCents } from '../../../core/money';

/** Wizard step 5 — server-computed estimate, mark complete, printable summary. */
@Component({
  selector: 'app-review',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './review.component.html',
  styleUrl: './review.component.css',
})
export class ReviewComponent {
  returnId = '';
  loading = signal<boolean>(false);
  error = signal<string>('');
  completed = signal<boolean>(false);

  // Mock estimate — service_agent clears this and loads via ApiService.getEstimate().
  estimate = signal<Estimate | null>({
    grossCents: 6850000,
    withholdingCents: 780000,
    itemizedCents: 1060000,
    standardCents: 1460000,
    deductionUsed: 'standard',
    deductionCents: 1460000,
    taxableCents: 5390000,
    taxCents: 764000,
    ctcCents: 200000,
    taxAfterCreditsCents: 564000,
    refundCents: 216000,
  });

  refundIsPositive = computed(() => (this.estimate()?.refundCents ?? 0) >= 0);

  fmt = formatCents;

  constructor(private route: ActivatedRoute, private router: Router) {
    this.returnId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  }

  back(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'deductions']);
  }

  markComplete(): void {
    // Mockup: service_agent will POST /returns/:id/complete here.
    this.completed.set(true);
  }

  print(): void {
    window.print();
  }

  done(): void {
    this.router.navigate(['/returns']);
  }
}
